import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a purchase request for a specific Name Icon.
 * Mirrors the server-side PurchaseNameIconEvent handler.
 */
export class PurchaseNameIconComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(iconId: number) {
        this._data = [iconId];
        console.log(
            `[📤] PurchaseNameIconComposer → attempting to buy name icon ${iconId}`
        );
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
